// Parse JSON output từ Groq (OpenAI-compatible) và chuẩn hoá
const raw = $input.first().json;
let content = raw?.choices?.[0]?.message?.content ?? raw;
if (typeof content === 'string') {
  content = content.replace(/```json|```/g, '').trim();
  content = JSON.parse(content);
}
return [{ json: {
  campaignId: $('Webhook: Generate').first().json.body.campaignId,
  captionVi: content.captionVi,
  captionEn: content.captionEn,
  hashtags: content.hashtags,
  imagePrompt: content.imagePrompt,
  platforms: $('Fetch Campaign Detail').first().json.platforms || []
} }];

// Dữ liệu resume do backend gửi vào khi user Duyệt.
// Wait node có thể bọc trong .body hoặc trả thẳng -> chuẩn hoá cả 2 trường hợp.
const item = $input.first().json || {};
const data = item.body && item.body.targets ? item.body : item;
return [{ json: {
  postId: data.postId,
  captionVi: data.captionVi,
  captionEn: data.captionEn,
  imageUrl: data.imageUrl,
  hashtags: data.hashtags || [],
  targets: data.targets || []
} }];

