// Chuẩn hoá kết quả đăng của từng target thành format callback.
// Graph API /photos trả { id, post_id }; nhánh lỗi (continueErrorOutput) mang item.json.error.
const body = $('Parse Resume Data').first().json;
const results = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const platform = j.platform || 'FACEBOOK';
  const postId = j.post_id || j.id || null;
  const ok = !j.error && !!postId;
  let errMsg = null;
  if (!ok) {
    const raw = j.error;
    errMsg = raw ? (raw.message || raw.error?.message || JSON.stringify(raw)) : 'Không đăng được (thiếu post_id)';
  }
  results.push({
    platform,
    success: ok,
    externalId: postId,
    permalink: postId ? `https://facebook.com/${postId}` : null,
    error: errMsg
  });
}
return [{ json: { postId: body.postId, results } }];
